_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
    ret = texture( sampler_main, vUv ).xyz;

    // darken (decay) over uTime
    ret *= 0.50; //or try: ret -= 0.004;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uv0 = vUv;
vec2 center = vec2 (.5+.5*q3,.5);
uv1 = (vUv-center)*uAspect.xy;
wmask = clamp01(128*uv1.y);
dist = .5/(uv1.y);
rs0.x = uv1.x * dist; rs0.y = dist ;

rs    = vec2 (rs0.x, rs0.y+uTime*speed)*wmask;
water = texture(sampler_noise_hq,rs) + texture(sampler_noise_hq,rs/3);
water -= 1.1;
uv_wat   = vec2(uv1.x, abs(uv1.y))-water*.1* wmask/dist;
uv_stars = vec2(uv1.x, abs(uv1.y))-water*.01* wmask;

sky1 = mix(q13*exp(-q14*abs(uv1.y)), .5-uv1.y,q15)*skycol;
sun = (.02/length(uv_wat-sunpos));

//hills
hill1 = q31*clamp01(16+16*texture(sampler_noise_mq,uv_wat.x*q10/2048+rand_preset.x)
           -q10*abs(uv_wat.y));

//stars
uv2 = 64*uv_stars;
smask = (texture(sampler_pw_noise_lq,uv2*q26/100+rand_preset.y )).b-.8 ;//changed to make random star postions
float stars = clamp01(.2/length(abs(fract(uv2)-.9))*smask)*(1-smask*8);
stars *= stars*q26;

//----------------Planet1----------------
vec2 rsk = (uv_stars - planpos) ;
vec2 dz1 = normalize(rsk);
float rad3 = q12*length(rsk);
vec2 uv4 =  tan(rad3)*dz1;
vec2 noise = abs(texture(sampler_noise_hq,uv4/2)-.5);
float mask3 = clamp01(100-71*rad3);
vec2 Planet = (uv4*(1+noise.x))*mask3;
vec2 pdist = sunpos-planpos;
float pla = clamp01(-.2+(dot(Planet,pdist)))/length(pdist)/2;

//forest
z = q11/uv_wat.x ;
uv2.x = abs(z)/2+sign(z)+uTime*.04*speed ;
float size = (texture(sampler_noise_hq,uv2.x/18)+.1);
uv2.y = (uv_wat.y*z/size-.5);
fmask = (uv2.y <= 0) * (uv2.y >= -1);
forest = clamp01(GetPixel(uv2*fmask)/abs(z)*2).g*fmask;

uv2.x = abs(z)/2+sign(z)+uTime*.035*speed ;;
//size = (texture(sampler_noise_hq,uv2.x/28)+.1);
uv2.x = abs(z)/2+sign(z)+uTime*.035*speed ;;
uv2.y = (uv_wat.y*z/size-.5);
fmask = (uv2.y <= 0) * (uv2.y >= -1);
forest += clamp01(GetPixel(uv2*fmask)/abs(z)*2).g*fmask*.7;

fmask = clamp01(1-forest*1.5);

ret = stars*clamp01(1-4*sun)+pow(sun,1)*suncol;
ret *= 1-mask3;
ret += pla*(suncol+skycol)/2;
ret *= 1-hill1;


uv2 = vec2(uv_wat.x*2-.5,uv_wat.y*4-.5);
float city  = GetPixel(uv2).r;
ret+= city*hill1*vec3 (1,.8,.5);

ret += clamp01(sky1)*skycol;
ret *= fmask;

uv2 = vec2(.5+uv1.x*.1,uv1.y*.75+.5);
fog = (GetBlur2(fract(uv2)).b)*q25;
ret = ret*clamp01(1-fog) + fog*(1+suncol);


rs    = vec2 (rs0.x, rs0.y+uTime*speed*.8+q30*sin(rs0.x*4))*wmask;
water = texture(sampler_noise_hq,rs) + texture(sampler_noise_hq,rs/4)-1;
float ice = clamp01(water.g*1 );
ret += ice*wmask*clamp01(sun*2)*4/dist*q20;

ret = 1-exp(-ret*2+.1);


//ret = GetPixel(vUv).g;



//Thanks Martin!

  fragColor = ret;
}
